import type {
  HTMLAttributes,
  ReactNode,
  FunctionComponent,
  InputHTMLAttributes,
} from 'react';
import type { WithRef } from '@andes/common';

type FormProps = WithRef<HTMLFormElement> & {
  children: ReactNode;
};

export const Form: FunctionComponent<
  FormProps & HTMLAttributes<HTMLFormElement>
>;

/**
 * Form allows the user to input data, and is a system defined by the relationship between
 * several form controls and their criteria of use.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/form | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/079dfc-forms/b/79514a | UI Specs}
 * @example
 * import { Form } from '@andes/form';
 *
 * const MyComponent = () => (
 *   <Form>
 *    <TextField label="Name" />
 *   </Form>
 * );
 */
export const FormComponent: FunctionComponent<FormProps>;

type HelperProps = InputHTMLAttributes<HTMLInputElement> & {
  children: ReactNode;

  /**
   * Component custom classname.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/form#props#helper | Documentation}
   */
  className?: string;

  /**
   * Unique identifier.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/form#props#helper | Documentation}
   */
  id?: string;

  /**
   * Modifier to apply different styles of the Helper.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/form#props#helper | Documentation}
   */
  modifier?: 'caution' | 'error';
};

export const Helper: FunctionComponent<HelperProps>;
